class Solution {
public:
    int longestDecomposition(string text) {
        int left = 0, right = text.size() - 1;
        int count = 0;
        string leftStr = "", rightStr = "";
        while (left < right) {
            leftStr += text[left++];
            rightStr = text[right--] + rightStr;
            if (leftStr == rightStr) {
                count += 2;
                leftStr = "";
                rightStr = "";
            }
        }
        return count + (left == right);
    }
};
